import{_ as a,o as d,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"光伏产业链","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/光伏/产业链.md","filePath":"电力新能源/光伏/产业链.md","lastUpdated":1781978464000}'),r={name:"电力新能源/光伏/产业链.md"};function e(o,t,l,i,h,p){return d(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="光伏产业链" tabindex="-1">光伏产业链 <a class="header-anchor" href="#光伏产业链" aria-label="Permalink to &quot;光伏产业链&quot;">​</a></h1><p><strong>成熟度：</strong> 主产业链产能过剩，新技术环节早期 <strong>PE/VC 重心：</strong> 钙钛矿叠层、BIPV、光伏回收、分布式运营平台 <strong>数据来源：</strong> China Energy MCP（国家能源局）、Prospector Energy MCP（NREL ATB + 美国并网队列） <strong>数据获取：</strong> 2026-06-15</p><hr><h2 id="一、产业链全景" tabindex="-1">一、产业链全景 <a class="header-anchor" href="#一、产业链全景" aria-label="Permalink to &quot;一、产业链全景&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上游（原材料）                 中游（制造）                 下游（应用）</span></span>
<span class="line"><span>────────────                  ──────────                 ──────────</span></span>
<span class="line"><span>硅料 (Polysilicon)  ──→      硅片 (Wafer)               电站开发</span></span>
<span class="line"><span>  ├── 西门子法（通威/协鑫）       ├── 单晶（隆基/中环）          ├── 集中式电站</span></span>
<span class="line"><span>  └── 颗粒硅（协鑫）            └── 金刚线切割                └── 分布式电站</span></span>
<span class="line"><span>                               ↓</span></span>
<span class="line"><span>                            电池片 (Cell)               运维服务</span></span>
<span class="line"><span>                              ├── PERC（成熟）               ├── 智能运维</span></span>
<span class="line"><span>                              ├── TOPCon（主力扩产）           └── 清洗/维修/检测</span></span>
<span class="line"><span>                              ├── HJT（布局期）</span></span>
<span class="line"><span>                              └── Perovskite（研发期）      回收利用</span></span>
<span class="line"><span>                               ↓                             └── 组件回收/材料剥离</span></span>
<span class="line"><span>                            组件 (Module)</span></span>
<span class="line"><span>                              + 逆变器/支架</span></span></code></pre></div><hr><h2 id="二、各环节分析" tabindex="-1">二、各环节分析 <a class="header-anchor" href="#二、各环节分析" aria-label="Permalink to &quot;二、各环节分析&quot;">​</a></h2><h3 id="_2-1-硅料" tabindex="-1">2.1 硅料 <a class="header-anchor" href="#_2-1-硅料" aria-label="Permalink to &quot;2.1 硅料&quot;">​</a></h3><ul><li><strong>工艺：</strong> 西门子法（主流）vs 颗粒硅（协鑫FBR法，降本路线）</li><li><strong>格局：</strong> 通威/协鑫/新特/大全/东方希望 CR5 &gt;80%</li><li><strong>状态：</strong> 产能严重过剩（2025年全球产能&gt;300万吨，需求&lt;150万吨），价格跌破现金成本</li><li><strong>趋势：</strong> 落后产能出清，颗粒硅渗透率提升</li><li><strong>一级机会：</strong> ⚠️ 当前不建议新进，等待整合完成</li></ul><h3 id="_2-2-硅片" tabindex="-1">2.2 硅片 <a class="header-anchor" href="#_2-2-硅片" aria-label="Permalink to &quot;2.2 硅片&quot;">​</a></h3><ul><li><strong>工艺：</strong> 单晶取代多晶已基本完成，N型取代P型进行中</li><li><strong>技术方向：</strong> 大尺寸(182/210)、薄片化(N型硅片&lt;130μm)</li><li><strong>主要玩家：</strong> 隆基/中环/弘元/京运通</li><li><strong>状态：</strong> 产能过剩严重，加工利润被压缩至极低水平</li><li><strong>一级机会：</strong> ⚠️ 为主，重点关注金刚线等辅材领域</li></ul><h3 id="_2-3-电池片" tabindex="-1">2.3 电池片 <a class="header-anchor" href="#_2-3-电池片" aria-label="Permalink to &quot;2.3 电池片&quot;">​</a></h3><p><strong>技术路线对比：</strong></p><table tabindex="0"><thead><tr><th>路线</th><th>量产效率</th><th>代表企业</th><th>扩产状态</th><th>一级机会</th></tr></thead><tbody><tr><td>PERC（P型）</td><td>23-23.5%</td><td>多家</td><td>停止扩产，存量替代</td><td>❌</td></tr><tr><td>TOPCon（N型）</td><td>25-26%</td><td>晶科/天合/通威/一道</td><td>当前扩产主力</td><td>⚠️ 产能过剩</td></tr><tr><td>HJT（N型）</td><td>25.5-26.5%</td><td>华晟/东方日升/金刚光伏</td><td>布局期，性价比待验证</td><td>✅ 设备+材料</td></tr><tr><td>BC（N型）</td><td>26.5-27%</td><td>隆基/爱旭</td><td>技术领先但工艺复杂</td><td>✅</td></tr><tr><td>Perovskite叠层</td><td>30-33%+（实验室）</td><td>极电/协鑫/纤纳/无限光能</td><td>中试线至GW级产线</td><td>✅✅ 最大机会</td></tr></tbody></table><p><strong>一级投资机会：</strong></p><ul><li><strong>钙钛矿/叠层</strong> — 技术突破阶段，重点关注GW级量产进程</li><li><strong>HJT 设备/靶材</strong> — 年化降本目标，辅材国产化</li><li><strong>技术平台型公司</strong> — 同时布局多条路线</li></ul><h3 id="_2-4-组件" tabindex="-1">2.4 组件 <a class="header-anchor" href="#_2-4-组件" aria-label="Permalink to &quot;2.4 组件&quot;">​</a></h3><ul><li>同质化严重，品牌+渠道+全球产能布局为差异点</li><li>出海壁垒高：反倾销/反补贴、碳足迹认证、本地化要求</li><li>一级机会很少（龙头已上市，制造属性强）</li></ul><h3 id="_2-5-配套环节-pe-vc-机会" tabindex="-1">2.5 配套环节（PE/VC 机会） <a class="header-anchor" href="#_2-5-配套环节-pe-vc-机会" aria-label="Permalink to &quot;2.5 配套环节（PE/VC 机会）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>环节</th><th>机会</th><th>逻辑</th></tr></thead><tbody><tr><td>逆变器</td><td>微逆/关断器(MLPE)</td><td>分布式安全标准趋严，国产替代</td></tr><tr><td>支架</td><td>跟踪支架</td><td>发电量增益 5-25%，渗透率提升空间大</td></tr><tr><td>光伏玻璃/胶膜</td><td>POE胶膜</td><td>N型双玻需求拉动高端封装材料</td></tr><tr><td>银浆</td><td>银包铜/铜电镀</td><td>降本方向（银占电池片成本~15%）</td></tr><tr><td>光伏回收</td><td>组件回收处理</td><td>2025后退役量爆发，政策强制在即</td></tr></tbody></table><hr><h2 id="三、中国市场装机与收益" tabindex="-1">三、中国市场装机与收益 <a class="header-anchor" href="#三、中国市场装机与收益" aria-label="Permalink to &quot;三、中国市场装机与收益&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>光伏累计装机（中国）</td><td><strong>8.9亿千瓦</strong>（890 GW）</td></tr><tr><td>2025年新增</td><td>约2.5亿千瓦</td></tr><tr><td>光伏年发电量</td><td>5,726亿千瓦时</td></tr><tr><td>光伏利用率</td><td>97.5%</td></tr><tr><td>集中式光伏IRR</td><td>5-8%（资本金）</td></tr><tr><td>分布式光伏IRR</td><td>6-10%（资本金，含余电上网收益）</td></tr></tbody></table><blockquote><p>利用率维持97%+表明消纳问题可控，但区域分化明显（青海91% vs 广东98.5%）</p></blockquote><p><strong>美国市场参考（Prospector Energy 并网队列）：</strong></p><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>纯太阳能项目数</td><td>17,252</td></tr><tr><td>总排队容量</td><td>1,384.6 GW</td></tr><tr><td>Solar+Storage混合</td><td>4,137项，704.8 GW</td></tr><tr><td>IRA ITC覆盖率</td><td>基础30%，最高50%（+能源社区+低收入附加）</td></tr></tbody></table><p><strong>NREL ATB 太阳能成本参考（Moderate Scenario, 2022基准）：</strong></p><table tabindex="0"><thead><tr><th>类别</th><th>LCOE ($/MWh)</th><th>CAPEX ($/kW)</th><th>容量因子</th></tr></thead><tbody><tr><td>商用光伏 Class 1（最佳）</td><td>64.9</td><td>2,058</td><td>18.9%</td></tr><tr><td>商用光伏 Class 5（中）</td><td>78.8</td><td>2,058</td><td>15.6%</td></tr><tr><td>商用光伏 Class 10（最差）</td><td>101.0</td><td>2,058</td><td>12.2%</td></tr></tbody></table><blockquote><p>美国LCOE约65-101 USD/MWh，中国光伏LCOE已降至30-50 USD/MWh 数据来源：<code>prospector-energy_get_technology_costs</code>（NREL Annual Technology Baseline）</p></blockquote><p><strong>中美光伏成本对比（一级视角）：</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>中国</th><th>美国</th></tr></thead><tbody><tr><td>组件成本</td><td>$0.08-0.10/W</td><td>$0.25-0.40/W（含关税）</td></tr><tr><td>LCOE</td><td>$30-50/MWh</td><td>$65-101/MWh</td></tr><tr><td>ITC抵免</td><td>补贴递减中</td><td>30-50%（IRA条款）</td></tr><tr><td>市场增速</td><td>增速放缓，存量替代</td><td>加速期，电网升级需求强</td></tr><tr><td>PE/VC机会</td><td>钙钛矿/分布式运维</td><td>项目融资/运维平台/ITC交易</td></tr></tbody></table><blockquote><p>🔗 数据来源：<code>china-energy_get_national_stats</code>, <code>china-energy_get_investment_ref</code>, <code>prospector-energy_get_queue_stats</code>, <code>prospector-energy_get_technology_costs</code></p></blockquote><hr><h2 id="四、产业链利润分布-2025-2026" tabindex="-1">四、产业链利润分布（2025-2026） <a class="header-anchor" href="#四、产业链利润分布-2025-2026" aria-label="Permalink to &quot;四、产业链利润分布（2025-2026）&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高利润区间: 逆变器（品牌溢价）、支架（跟踪系统）、POE胶膜（技术壁垒）</span></span>
<span class="line"><span>中利润区间: TOPCon电池片（阶段性技术红利）</span></span>
<span class="line"><span>低/负利润: 硅料、硅片、组件（产能过剩，毛利率&lt;5%）</span></span></code></pre></div><hr><h2 id="五、关键趋势判研" tabindex="-1">五、关键趋势判研 <a class="header-anchor" href="#五、关键趋势判研" aria-label="Permalink to &quot;五、关键趋势判研&quot;">​</a></h2><ol><li><strong>产能出清路径</strong> — 2025-2027是出清期，谁现金流最健康谁活下来</li><li><strong>技术迭代窗口</strong> — Perovskite叠层是下一个价值高地，2027-2028有望规模量产</li><li><strong>出海2.0</strong> — 不仅是组件出口，更是产能出海（中东/东南亚/美国本土化）</li><li><strong>分布式占比持续提升</strong> — 商业模式创新（光伏+储能+充电）</li><li><strong>光伏+AI</strong> — 智能运维、功率预测、虚拟电厂聚合</li></ol><hr><h2 id="六、交叉链接" tabindex="-1">六、交叉链接 <a class="header-anchor" href="#六、交叉链接" aria-label="Permalink to &quot;六、交叉链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>关联赛道</th><th>链接</th><th>说明</th></tr></thead><tbody><tr><td><strong>算电协同</strong></td><td><a href="./../算电协同/赛道总览#42-算力西迁--绿电消纳">赛道总览</a></td><td>绿电直购+源网荷储一体化</td></tr><tr><td><strong>储能</strong></td><td><a href="./../储能/产业链">产业链</a></td><td>光储一体化确定性趋势</td></tr><tr><td><strong>AI 应用层</strong></td><td><a href="./../../AI/应用层/AI应用赛道#17-ai能源重点交叉">AI+能源</a></td><td>光伏功率预测+智能运维</td></tr></tbody></table>`,41)])])}const b=a(r,[["render",e]]);export{g as __pageData,b as default};
